// Pega o IDFINANC MAIOR (mais recente) — gerado pelo FopRotinas atual
const resp = $input.first().json;
let ids = [];

if (Array.isArray(resp)) ids = resp.map(r => r.IDFINANC).filter(Boolean);
else if (resp && resp.IDFINANC) ids = [resp.IDFINANC];
else if (resp && Array.isArray(resp[0])) ids = resp[0].map(r => r.IDFINANC).filter(Boolean);

if (ids.length === 0) {
  throw new Error('Nenhum IDFINANC retornado');
}

const staticData = $getWorkflowStaticData('global');
const integrados = new Set(staticData.idsIntegrados || []);

const novos = ids.filter(id => !integrados.has(id));
let idAtual;
if (novos.length > 0) {
  idAtual = Math.max(...novos);
} else {
  idAtual = Math.max(...ids);
}

const loopMeta = $('Loop Eventos').item.json;
return [{
  json: {
    ...loopMeta,
    idFinanc: idAtual,
    IDFINANC: idAtual
  }
}];

const input = $input.first().json;

if (!Array.isArray(input.chapas) || input.chapas.length === 0) {
  throw new Error('Input invalido: chapas[] vazio ou ausente');
}
if (!Array.isArray(input.eventos) || input.eventos.length === 0) {
  throw new Error('Input invalido: eventos[] vazio ou ausente');
}

const hoje = new Date();
const pad = n => String(n).padStart(2, '0');
const dataIso = `${hoje.getFullYear()}-${pad(hoje.getMonth() + 1)}-${pad(hoje.getDate())}`;

let mesCompAtual = input.mesComp - 1;
let anoCompAtual = input.anoComp;
if (mesCompAtual < 1) { mesCompAtual = 12; anoCompAtual -= 1; }

const tz = -hoje.getTimezoneOffset();
const tzSign = tz >= 0 ? '+' : '-';
const tzHH = pad(Math.floor(Math.abs(tz) / 60));
const tzMM = pad(Math.abs(tz) % 60);
const scheduleDateTime = `${dataIso}T${pad(hoje.getHours())}:${pad(hoje.getMinutes())}:${pad(hoje.getSeconds())}.0000000${tzSign}${tzHH}:${tzMM}`;

const uuid = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
});

// 1 item por evento → cada evento entra no loop
return input.eventos.map(ev => ({
  json: {
    ...input,
    eventoAtual: ev,
    dataEmissao: `${dataIso}T00:00:00`,
    dataIso,
    scheduleDateTime,
    executionId: uuid(),
    mesCompAtual,
    anoCompAtual,
    chapasXml: input.chapas.map(c => `<a:string>${c}</a:string>`).join('\n      '),
    eventosXml: `<a:string>${ev}</a:string>`,
    chapaAtual: input.chapas[0]
  }
}));

const staticData = $getWorkflowStaticData('global');
staticData.idsIntegrados = staticData.idsIntegrados || [];

const it = $input.first().json;
const id = $('Montar SOAP IntegrarBackOffices1').item.json.idFinanc;

const xml = String(it.data || it.body || JSON.stringify(it));
const m = xml.match(/<ExecuteWithXmlParamsResult>(\d+)<\/ExecuteWithXmlParamsResult>/);
const ok = m && parseInt(m[1]) === 1;

if (ok && id && !staticData.idsIntegrados.includes(id)) {
  staticData.idsIntegrados.push(id);
}

return [{
  json: {
    idFinanc: id,
    ok,
    eventoAtual: $('Loop Eventos').item.json.eventoAtual,
    totalIntegrados: staticData.idsIntegrados.length
  }
}];

const staticData = $getWorkflowStaticData('global');
const integrados = staticData.idsIntegrados || [];
const meta = $('When Executed by Another Workflow').first().json;

staticData.idsIntegrados = [];

return [{
  json: {
    sucesso: true,
    contrato: meta.contrato,
    competencia: `${meta.mesComp}/${meta.anoComp}`,
    totalChapas: meta.chapas.length,
    totalEventos: meta.eventos.length,
    eventos: meta.eventos,
    idsIntegrados: integrados,
    totalIntegrados: integrados.length
  }
}];

const loop = $('Loop Eventos').item.json;
const evento = String(loop.eventoAtual || '');
const beneficio = evento === '100'
  ? 'VR (alimentação)'
  : evento === '110'
    ? 'VT (transporte)'
    : `desconhecido (evento ${evento})`;

const pad = n => String(n).padStart(2, '0');
const competencia = `${pad(loop.mesComp)}/${loop.anoComp}`;

let idFinanc = '—';
try { idFinanc = $('Pegar Ultimo IDFINANC').item.json.idFinanc || '—'; } catch (e) {}

const mensagem = [
  'Erro ao lançar no Protheus',
  `Chapa: ${loop.chapaAtual}`,
  `Benefício: ${beneficio}`,
  `Contrato: ${loop.contrato}`,
  `Competência: ${competencia}`,
  `IDFINANC: ${idFinanc}`
].join('\n');

return [{ json: { Destinatário: '120363400013959285@g.us', Mensagem: mensagem } }];
